import functools, time

class ToolResultCache:
    def __init__(self, redis_client, ttl_map: dict[str, int | None]):
        self.r       = redis_client
        self.ttl_map = ttl_map
        self.hits    = 0
        self.misses  = 0

    def get(self, tool_name: str, tool_input: dict):
        """Return cached result or None."""
        ttl = self.ttl_map.get(tool_name)
        if ttl is None:
            return None  # tool is uncacheable
        key   = cache_key(tool_name, tool_input)
        value = self.r.get(key)
        if value is not None:
            self.hits += 1
            return json.loads(value)
        self.misses += 1
        return None

    def set(self, tool_name: str, tool_input: dict, result) -> None:
        ttl = self.ttl_map.get(tool_name)
        if ttl is None:
            return
        key = cache_key(tool_name, tool_input)
        self.r.setex(key, ttl, json.dumps(result, ensure_ascii=False))

    @property
    def hit_rate(self) -> float:
        total = self.hits + self.misses
        return self.hits / total if total else 0.0


cache = ToolResultCache(r, TOOL_TTL)

def execute_tool_with_cache(
    tool_name: str,
    tool_input: dict,
    real_executor,   # callable(tool_name, tool_input) -> Any
) -> tuple[any, bool]:
    """Returns (result, was_cached)."""
    cached = cache.get(tool_name, tool_input)
    if cached is not None:
        return cached, True

    result = real_executor(tool_name, tool_input)
    cache.set(tool_name, tool_input, result)
    return result, False

import anthropic

client = anthropic.Anthropic()

def real_tool_executor(tool_name: str, inputs: dict) -> str:
    """Your actual tool implementations."""
    if tool_name == "get_weather":
        return fetch_weather(inputs["city"], inputs.get("units", "metric"))
    if tool_name == "search_documentation":
        return search_docs(inputs["query"])
    raise ValueError(f"Unknown tool: {tool_name}")


def run_agent_with_cache(messages: list[dict], tools: list[dict]) -> str:
    while True:
        response = client.messages.create(
            model="claude-opus-4-8",
            max_tokens=4096,
            messages=messages,
            tools=tools,
        )

        if response.stop_reason != "tool_use":
            return response.content[0].text

        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue

            result, was_cached = execute_tool_with_cache(
                block.name, block.input, real_tool_executor
            )
            tool_results.append({
                "type":        "tool_result",
                "tool_use_id": block.id,
                "content":     str(result),
            })

        messages = messages + [
            {"role": "assistant", "content": response.content},
            {"role": "user",      "content": tool_results},
        ]

import sqlparse

def is_read_only_sql(query: str) -> bool:
    """True if the query is a read-only SELECT."""
    parsed = sqlparse.parse(query.strip())
    if not parsed:
        return False
    stmt_type = parsed[0].get_type()
    return stmt_type == "SELECT"


STABLE_TABLES = {"products", "categories", "countries", "config"}

def sql_cache_ttl(query: str, tables_touched: set[str]) -> int | None:
    """Return TTL if the query is safe to cache, else None."""
    if not is_read_only_sql(query):
        return None
    if tables_touched.issubset(STABLE_TABLES):
        return 3600  # stable reference data: 1 hour
    return None     # live transactional data: no cache

def invalidate_tool_cache(tool_name: str, tool_input: dict) -> bool:
    """Delete a specific cached result. Returns True if the key existed."""
    key = cache_key(tool_name, tool_input)
    return bool(r.delete(key))


def invalidate_by_prefix(tool_name: str) -> int:
    """Delete ALL cached results for a tool (e.g. after a bulk update)."""
    pattern = f"tool:{tool_name}:*"
    keys = r.keys(pattern)  # safe on small key spaces; use SCAN for large
    if keys:
        return r.delete(*keys)
    return 0


# Example: after updating product data, clear all search_documentation results
def after_docs_update():
    count = invalidate_by_prefix("search_documentation")
    print(f"Invalidated {count} cached documentation search results")
